  1→import {
  2→  createContext,
  3→  useCallback,
  4→  useContext,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→
 10→export interface NavigationEntry<T = unknown> {
 11→  title: string;
 12→  data: T;
 13→}
 14→
 15→export type TransitionDirection = 'push' | 'pop' | 'none';
 16→
 17→interface NavigationState<T> {
 18→  stack: NavigationEntry<T>[];
 19→  direction: TransitionDirection;
 20→}
 21→
 22→export interface NavigationContext<T = unknown> {
 23→  push: (title: string, data: T) => void;
 24→  pop: () => void;
 25→  popToRoot: () => void;
 26→  currentEntry: NavigationEntry<T> | null;
 27→  breadcrumbs: {
 28→    label: string;
 29→    onBack?: () => void;
 30→  }[];
 31→  canGoBack: boolean;
 32→  direction: TransitionDirection;
 33→  stackDepth: number;
 34→}
 35→
 36→// eslint-disable-next-line @typescript-eslint/no-explicit-any
 37→const NavContext = createContext<NavigationContext<any> | null>(null);
 38→
 39→export const NavigationContextProvider = NavContext.Provider;
 40→
 41→export function useNavigation<T = unknown>(): NavigationContext<T> {
 42→  const ctx = useContext(NavContext);
 43→  if (!ctx) {
 44→    throw new Error('useNavigation must be used within a NavigationProvider');
 45→  }
 46→  return ctx as NavigationContext<T>;
 47→}
 48→
 49→export function useNavigationStack<T = unknown>(
 50→  rootTitle: string,
 51→): NavigationContext<T> {
 52→  const [state, setState] = useState<NavigationState<T>>({
 53→    stack: [],
 54→    direction: 'none',
 55→  });
 56→
 57→  const stackRef = useRef(state.stack);
 58→  stackRef.current = state.stack;
 59→
 60→  const push = useCallback((title: string, data: T) => {
 61→    setState(prev => ({
 62→      stack: [
 63→        ...prev.stack,
 64→        {
 65→          title,
 66→          data,
 67→        },
 68→      ],
 69→      direction: 'push',
 70→    }));
 71→  }, []);
 72→
 73→  const pop = useCallback(() => {
 74→    if (stackRef.current.length === 0) return;
 75→    setState(prev => ({
 76→      stack: prev.stack.slice(0, -1),
 77→      direction: 'pop',
 78→    }));
 79→  }, []);
 80→
 81→  const popToRoot = useCallback(() => {
 82→    if (stackRef.current.length === 0) return;
 83→    setState({
 84→      stack: [],
 85→      direction: 'pop',
 86→    });
 87→  }, []);
 88→
 89→  const currentEntry: NavigationEntry<T> | null =
 90→    state.stack.length > 0 ? state.stack[state.stack.length - 1]! : null;
 91→
 92→  const canGoBack = state.stack.length > 0;
 93→
 94→  const breadcrumbs = useMemo(() => {
 95→    if (state.stack.length === 0) return [];
 96→
 97→    const crumbs: {
 98→      label: string;
 99→      onBack?: () => void;
100→    }[] = [
101→      {
102→        label: rootTitle,
103→        onBack: () => {
104→          setState({
105→            stack: [],
106→            direction: 'pop',
107→          });
108→        },
109→      },
110→    ];
111→
112→    for (let i = 0; i < state.stack.length; i++) {
113→      const entry = state.stack[i]!;
114→      const isLast = i === state.stack.length - 1;
115→      if (isLast) {
116→        crumbs.push({ label: entry.title });
117→      } else {
118→        const targetDepth = i + 1;
119→        crumbs.push({
120→          label: entry.title,
121→          onBack: () => {
122→            setState(prev => ({
123→              stack: prev.stack.slice(0, targetDepth),
124→              direction: 'pop',
125→            }));
126→          },
127→        });
128→      }
129→    }
130→
131→    return crumbs;
132→  }, [
133→    state.stack,
134→    rootTitle,
135→  ]);
136→
137→  return useMemo(
138→    () => ({
139→      push,
140→      pop,
141→      popToRoot,
142→      currentEntry,
143→      breadcrumbs,
144→      canGoBack,
145→      direction: state.direction,
146→      stackDepth: state.stack.length,
147→    }),
148→    [
149→      push,
150→      pop,
151→      popToRoot,
152→      currentEntry,
153→      breadcrumbs,
154→      canGoBack,
155→      state.direction,
156→      state.stack.length,
157→    ],
158→  );
159→}
