 72→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 73→  switch (entry.type) {
 74→    case 'label':
 75→      return (
 76→        <DetailMetadata.Label
 77→          key={index}
 78→          title={entry.title}
 79→          text={entry.text}
 80→        />
 81→      );
 82→    case 'link':
 83→      return (
 84→        <DetailMetadata.Link
 85→          key={index}
 86→          title={entry.title}
 87→          text={entry.text}
 88→          target={entry.target}
 89→        />
 90→      );
 91→    case 'tag-list':
 92→      return (
 93→        <DetailMetadata.TagList key={index} title={entry.title}>
 94→          {entry.tags.map(tag => (
 95→            <DetailMetadata.Tag
 96→              key={tag.text}
 97→              text={tag.text}
 98→              color={tag.color}
 99→            />
100→          ))}
101→        </DetailMetadata.TagList>
102→      );
103→    case 'separator':
104→      return <DetailMetadata.Separator key={index} />;
105→  }
106→}
