140→interface SnippetFormState {
141→  name: string;
142→  keyword: string;
143→  snippet: string;
144→  category: string;
145→  isShared: boolean;
146→  expiresAt: string;
147→}
148→
149→const INITIAL_SNIPPET_FORM: SnippetFormState = {
150→  name: '',
151→  keyword: '',
152→  snippet: '',
153→  category: 'general',
154→  isShared: false,
155→  expiresAt: '',
156→};
157→
158→const SNIPPET_CATEGORIES = [
159→  {
160→    label: 'General',
161→    value: 'general',
162→  },
163→  {
164→    label: 'Code',
165→    value: 'code',
166→  },
167→  {
168→    label: 'Email',
169→    value: 'email',
170→  },
171→  {
172→    label: 'Template',
173→    value: 'template',
174→  },
175→];
